import{_ as r,o as l,c as e,Y as i}from"./chunks/framework.TarpMSr5.js";import"./chunks/theme.D3ILKLax.js";const b=JSON.parse('{"title":"隐私政策","description":"CRUDClass BLOG隐私政策声明","frontmatter":{"title":"隐私政策","description":"CRUDClass BLOG隐私政策声明","date":"2022-12-12T13:42:34.000Z","updated":"2022-12-12T13:42:34.000Z"},"headers":[],"relativePath":"privacy.md","filePath":"privacy.md"}'),o={name:"privacy.md"};function t(s,a,n,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[i('<h2 id="隐私政策" tabindex="-1">隐私政策 <a class="header-anchor" href="#隐私政策" aria-label="Permalink to “隐私政策”">​</a></h2><h3 id="📋-引言" tabindex="-1">📋 引言 <a class="header-anchor" href="#📋-引言" aria-label="Permalink to “📋 引言”">​</a></h3><p>欢迎访问 CRUDClass BLOG（以下简称&quot;本博客&quot;）。我们高度重视用户的隐私保护，本隐私政策旨在说明我们如何收集、使用、存储和保护您的个人信息。请仔细阅读本政策，了解我们对您个人信息的处理方式。</p><h3 id="📊-信息收集" tabindex="-1">📊 信息收集 <a class="header-anchor" href="#📊-信息收集" aria-label="Permalink to “📊 信息收集”">​</a></h3><h4 id="_1-自动收集的信息" tabindex="-1">1. 自动收集的信息 <a class="header-anchor" href="#_1-自动收集的信息" aria-label="Permalink to “1. 自动收集的信息”">​</a></h4><p>当您访问本博客时，我们可能会自动收集以下信息：</p><ul><li><strong>访问日志</strong>：IP地址、浏览器类型、操作系统、访问时间、页面浏览记录</li><li><strong>设备信息</strong>：设备类型、屏幕分辨率、语言设置</li><li><strong>Cookies</strong>：用于改善用户体验的匿名标识符</li></ul><h4 id="_2-您主动提供的信息" tabindex="-1">2. 您主动提供的信息 <a class="header-anchor" href="#_2-您主动提供的信息" aria-label="Permalink to “2. 您主动提供的信息”">​</a></h4><p>当您通过以下方式与我们互动时，可能会提供个人信息：</p><ul><li><strong>评论功能</strong>：如果您在本博客发表评论，可能需要提供姓名和邮箱</li><li><strong>联系表单</strong>：通过邮箱联系我们时提供的联系信息</li><li><strong>订阅功能</strong>：如果未来提供订阅服务，可能需要提供邮箱地址</li></ul><h3 id="🎯-信息使用" tabindex="-1">🎯 信息使用 <a class="header-anchor" href="#🎯-信息使用" aria-label="Permalink to “🎯 信息使用”">​</a></h3><p>我们收集的信息主要用于以下目的：</p><ol><li><strong>提供服务</strong>：确保博客正常访问和功能使用</li><li><strong>改进体验</strong>：分析用户行为以优化内容和功能</li><li><strong>安全保障</strong>：防止恶意攻击和滥用行为</li><li><strong>法律合规</strong>：遵守相关法律法规要求</li></ol><h3 id="🔒-信息保护" tabindex="-1">🔒 信息保护 <a class="header-anchor" href="#🔒-信息保护" aria-label="Permalink to “🔒 信息保护”">​</a></h3><p>我们采取合理的技术和组织措施保护您的个人信息：</p><ul><li><strong>技术措施</strong>：使用HTTPS加密传输、定期安全更新</li><li><strong>访问控制</strong>：限制对个人信息的访问权限</li><li><strong>数据最小化</strong>：仅收集必要的信息，定期清理过期数据</li></ul><h3 id="📤-信息共享" tabindex="-1">📤 信息共享 <a class="header-anchor" href="#📤-信息共享" aria-label="Permalink to “📤 信息共享”">​</a></h3><p>我们承诺不会出售、交易或出租您的个人信息给第三方。仅在以下情况下可能共享信息：</p><ol><li><strong>法律要求</strong>：根据法律法规或政府机关的要求</li><li><strong>服务提供商</strong>：与必要的技术服务提供商共享（如托管服务商）</li><li><strong>保护权益</strong>：为保护本博客、用户或公众的合法权益</li></ol><h3 id="🍪-cookies使用" tabindex="-1">🍪 Cookies使用 <a class="header-anchor" href="#🍪-cookies使用" aria-label="Permalink to “🍪 Cookies使用”">​</a></h3><p>本博客使用Cookies来：</p><ul><li><strong>记住偏好</strong>：如语言选择、主题设置</li><li><strong>分析流量</strong>：通过Google Analytics等工具分析访问情况</li><li><strong>功能支持</strong>：支持评论、分享等交互功能</li></ul><p>您可以通过浏览器设置管理或禁用Cookies，但这可能会影响某些功能的正常使用。</p><h3 id="🔗-第三方链接" tabindex="-1">🔗 第三方链接 <a class="header-anchor" href="#🔗-第三方链接" aria-label="Permalink to “🔗 第三方链接”">​</a></h3><p>本博客可能包含指向第三方网站的链接。请注意，这些网站有各自的隐私政策，我们不对其内容或隐私实践负责。建议您在访问这些网站时查看其隐私政策。</p><h3 id="👶-儿童隐私" tabindex="-1">👶 儿童隐私 <a class="header-anchor" href="#👶-儿童隐私" aria-label="Permalink to “👶 儿童隐私”">​</a></h3><p>本博客不面向13岁以下的儿童。我们不会故意收集儿童的个人信息。如果您是家长或监护人，并认为您的孩子向我们提供了个人信息，请与我们联系，我们将尽快删除这些信息。</p><h3 id="📝-政策更新" tabindex="-1">📝 政策更新 <a class="header-anchor" href="#📝-政策更新" aria-label="Permalink to “📝 政策更新”">​</a></h3><p>我们可能会不时更新本隐私政策。更新后的政策将在本页面发布，并更新顶部的&quot;最后更新&quot;日期。建议您定期查看本政策以了解最新变化。</p><h3 id="📞-联系我们" tabindex="-1">📞 联系我们 <a class="header-anchor" href="#📞-联系我们" aria-label="Permalink to “📞 联系我们”">​</a></h3><p>如果您对本隐私政策有任何疑问、意见或建议，请通过以下方式联系我们：</p><ul><li><strong>邮箱</strong>: <a href="mailto:calmly_li@outlook.com" target="_blank" rel="noreferrer">calmly_li@outlook.com</a></li><li><strong>GitHub Issues</strong>: <a href="https://github.com/CRUDClass/vitepress_blog/issues" target="_blank" rel="noreferrer">CRUDClass/vitepress_blog</a></li></ul><h3 id="⚖️-法律适用" tabindex="-1">⚖️ 法律适用 <a class="header-anchor" href="#⚖️-法律适用" aria-label="Permalink to “⚖️ 法律适用”">​</a></h3><p>本隐私政策受中华人民共和国法律管辖。任何因本政策引起的争议，应首先通过友好协商解决；协商不成的，应向有管辖权的人民法院提起诉讼。</p><hr><p><strong>最后更新</strong>: 2022-12-12 13:42:34</p>',36)])])}const _=r(o,[["render",t]]);export{b as __pageData,_ as default};
